import axios from 'axios';

const API_BASE_URL = process.env.VUE_APP_API_BASE_URL || 'http://localhost:3000';

// Create axios instance with default config
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Get all schedules for a user
export const getUserSchedules = async (userId) => {
  try {
    const response = await api.get(`/api/schedules/user/${userId}`);
    return response.data.data;
  } catch (error) {
    console.error('Error fetching user schedules:', error);
    throw error;
  }
};

// Get today's schedules for a user
export const getTodaySchedules = async (userId) => {
  try {
    const response = await api.get(`/api/schedules/user/${userId}/today`);
    return response.data.data;
  } catch (error) {
    console.error('Error fetching today schedules:', error);
    throw error;
  }
};

// Get a specific schedule by ID
export const getScheduleById = async (scheduleId) => {
  try {
    const response = await api.get(`/api/schedules/${scheduleId}`);
    return response.data.data;
  } catch (error) {
    console.error('Error fetching schedule:', error);
    throw error;
  }
};

// Create a new schedule
export const createSchedule = async (scheduleData) => {
  try {
    const response = await api.post('/api/schedules', scheduleData);
    return response.data.data;
  } catch (error) {
    console.error('Error creating schedule:', error);
    throw error;
  }
};

// Update a schedule
export const updateSchedule = async (scheduleId, scheduleData) => {
  try {
    const response = await api.put(`/api/schedules/${scheduleId}`, scheduleData);
    return response.data.data;
  } catch (error) {
    console.error('Error updating schedule:', error);
    throw error;
  }
};

// Delete a schedule
export const deleteSchedule = async (scheduleId) => {
  try {
    const response = await api.delete(`/api/schedules/${scheduleId}`);
    return response.data;
  } catch (error) {
    console.error('Error deleting schedule:', error);
    throw error;
  }
};

// Update schedule status
export const updateScheduleStatus = async (scheduleId, status) => {
  try {
    const response = await api.patch(`/api/schedules/${scheduleId}/status`, { status });
    return response.data.data;
  } catch (error) {
    console.error('Error updating schedule status:', error);
    throw error;
  }
};

export default {
  getUserSchedules,
  getTodaySchedules,
  getScheduleById,
  createSchedule,
  updateSchedule,
  deleteSchedule,
  updateScheduleStatus,
};
